# 输入获取
s1 = input()
s2 = input()


# 解析版本号字符串s
def getVersion(s):
    patch = ""
    mile = ""

    i = s.find("-")

    # 找到第一个“-”,先把里程碑解析出来,因为里程碑中可能含有"-"和".",因此必须先处理掉
    major_minor_patch = ""
    if i != -1:
        mile = s[i + 1:]
        major_minor_patch = s[0:i]
    else:
        major_minor_patch = s

    # 之后再处理非里程碑部分
    tmp = major_minor_patch.split(".")
    major = int(tmp[0])
    minor = int(tmp[1])

    if len(tmp) > 2:
        patch = int(tmp[2])

    return major, minor, patch, mile


# 算法入口
def getResult(s1, s2):
    major1, minor1, patch1, mile1 = getVersion(s1)
    major2, minor2, patch2, mile2 = getVersion(s2)

    if major1 > major2:
        return s1
    elif major1 < major2:
        return s2

    if minor1 > minor2:
        return s1
    elif minor1 < minor2:
        return s2

    if patch1 != "" or patch2 != "":
        if patch2 == "":
            return s1
        elif patch1 == "":
            return s2

        # 走到此步,说明s1,s2的增量版本都不是空串,此当成数字进行比较
        if patch1 > patch2:
            return s1
        elif patch1 < patch2:
            return s2

    # s1,s2的里程碑的空串判断,同增量版本
    if mile2 == "":
        return s1
    elif mile1 == "":
        return s2

    # 如果s1,s2的里程碑版本都不是空串,则按照字典序比较
    return s1 if mile1 >= mile2 else s2


# 算法调用
print(getResult(s1, s2))
